33	static std::string format_time(const std::chrono::system_clock::time_point & now, const std::string & format) {
34	    auto               time       = std::chrono::system_clock::to_time_t(now);
35	    auto               local_time = *std::localtime(&time);
36	    std::ostringstream ss;
37	    ss << std::put_time(&local_time, format.c_str());
38	    auto res = ss.str();
39	    return res;
40	}
41	
42	static json safe_args_parse(const std::string & to_parse) {
43	    std::string stripped = to_parse;
44	    if (to_parse.at(0) == '"' && to_parse.at(to_parse.length() - 1) == '"') {
45	        stripped = to_parse.substr(1, to_parse.length() - 1);
46	    }
47	    try {
48	        return json::parse(stripped);
49	    } catch (json::exception & e) {
50	        return stripped;
51	    }
52	}
