15	std::string trim_whitespace(const std::string & str) {
16	    size_t start = 0;
17	    while (start < str.length() && std::isspace(static_cast<unsigned char>(str[start]))) {
18	        start++;
19	    }
20	
21	    if (start == str.length()) {
22	        return "";
23	    }
24	
25	    size_t end = str.length() - 1;
26	    while (end > start && std::isspace(static_cast<unsigned char>(str[end]))) {
27	        end--;
28	    }
29	
30	    return str.substr(start, end - start + 1);
31	}
